  assert x == gcc;
  assert (ly + ry) / 2 == gcr && (lx + rx) / 2 == gcc;
  assert y == gcr && x == gcc;
  assert gcc - ghalf <= lx <= gcc + ghalf;
  assert grid[ly][gcc - ghalf] == 'B';
  assert grid[ly][gcc + ghalf] == 'B';
  ProveExistsH(n, m, grid, r - 1, c - 1, ghalf);
