  if lx < gcc - ghalf {
    assert !CellInSquare(ly, lx, gcr, gcc, ghalf);
    assert !CellInSquare(ly, lx, gcr, gcc, ghalf);
    assert grid[ly][lx] == 'B';
  }
  assert lx == gcc - ghalf;

