      assert grid[ly][gcc - ghalf] == 'B';
      assert grid[ly][gcc] == 'B';
    }
    rx := rx + 1;
  }
  if rx <= gcc + ghalf {
    assert grid[ly][gcc + ghalf] == 'B';
    assert cellInSquare(ly, lx, gcr, gcc, ghalf);
    assert cellInSquare(ly, lx, gcr, gcc, ghalf);
  }
  assert grid[ly][gcc] == 'B';

  // Compute center
  var y := (ly + ry) / 2;
  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

  assert y == gcr;
  assert y == gcr;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert x == gcc;
  assert lx + rx == 2 * gcc + 1;
  assert grid[ly][gcc + ghalf] == 'B';
  assert grid[ly][gcc - ghalf] == 'B';
  assert grid[ly][gcc + ghalf] == 'B';
  ProveExistsH(n, m, grid, r - 1, c - 1, ghalf);
}

