      assert grid[ly][gcc + ghalf] != 'B';
      assert rx == gcc + ghalf + 1;
    }
    rx := rx + 1;
  }
  if rx <= gcc + ghalf {
    assert rx == gcc + ghalf + 1;
    assert grid[ly][gcc + ghalf] != 'B';
    assert grid[ly][gcc + ghalf] != 'B';
  }
  assert rx == gcc + ghalf + 1;

  // Compute center
  var y := (ly + ry) / 2;
  var x := (lx + rx) / 2;
  r := y + 1;
  c := x + 1;

  assert y == gcr;
  assert y == gcr;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert lx + rx == 2 * gcc + 1;
  assert x == gcc;
  assert x == gcc;
  assert x == gcc;
  assert x == gcc;
  ProveExistsH(n, m, grid, r - 1, c - 1, ghalf);
}

